onClick:
{{
  (async () => {
    // 1. Lấy dữ liệu từ các ô Input
    const maVatLieu = inp_BP_Ma.text.trim();
    const soLuong = Number(inp_BP_SoLuong.text);

    // 2. Kiểm tra dữ liệu đầu vào
    if (!maVatLieu || !soLuong || soLuong <= 0) {
        showAlert("❌ Vui lòng nhập Mã và Số lượng hợp lệ!", "error");
        return;
    }

    try {
        showAlert("⏳ Đang xử lý báo phế...", "info");

        // 3. Lưu vào bảng scrap_management
        await Action_Form_AddScrap.run({
            ma: maVatLieu, 
            so_luong: soLuong, 
            ten: inp_BP_Ten.text || '', 
            xuong: inp_BP_Xuong.text || '',
            don_vi: inp_BP_DonVi.text || '', 
            nguoi_dat: inp_BP_NguoiDat.text || '', 
            loai: inp_BP_Loai.text || '',
            vi_tri: inp_BP_ViTri.text || '', 
            nguyen_nhan: inp_BP_NguyenNhan.text || '', 
            nguoi_duyet: inp_BP_NguoiDuyet.text || ''
        });

        // 4. Gọi các Query trừ kho và ghi lịch sử
        // Đảm bảo truyền đủ tham số 'ma' và 'so_luong' khớp với {{ this.params.ma }} trong SQL
        await Action_Export_KhoCongCu.run({ ma: maVatLieu, so_luong: soLuong });
        await Action_Export_KhoPhuTung.run({ ma: maVatLieu, so_luong: soLuong });

        showAlert("✅ Đã xử lý báo phế và cập nhật kho thành công!", "success");

        // 5. Reset form
        // LƯU Ý QUAN TRỌNG: Bạn cần thay 'Tên_Form_Của_Bạn' bằng tên widget Form/Container thật.
        // Cách xem: Nhấn vào Form, nhìn bảng Properties cột phải -> mục Name.
        resetWidget('Tên_Widget_Form_Của_Bạn', true); 

        // 6. Refresh lại bảng dữ liệu
        await Get_Scrap_List.run();

    } catch (err) {
        console.error("Lỗi chi tiết:", err);
        showAlert("❌ Lỗi: " + err.message, "error");
    }
  })()
}}
